# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request
from models import User  # Assuming you have a User model in models module

app = Flask(__name__)

@app.route('/api/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    current_user = User.get('current_admin')  # Get the current admin user from your database
    
    if not current_user or not current_user.role == 'admin':
        return {'error': 'Unauthorized'}, 401

    user = User.query.filter(User.id==user_id).first()

    if not user:
        return {'error': 'User not found'}, 404
    
    data = request.get_json()

    if 'email' in data:
        user.email = data['email']
    if 'username' in data:
        user.username = data['username']
    if 'role' in data and current_user.role != 'moderator':  # Moderators can only change their own roles
        user.role = data['role']
    if 'account_status' in data and current_user.role == 'admin':
        user.account_status = data['account_status']
    if 'subscription_tier' in data and current_user.role == 'admin':
        user.subscription_tier = data['subscription_tier']
    
    User.session.commit()  # Commit the changes to the database

    return {'message': 'User updated successfully'}, 200